32: /**
33:  * A {@link WindowAssigner} that windows elements into sessions based on the timestamp of the
34:  * elements. Windows cannot overlap.
35:  *
36:  * <p>For example, in order to window into windows of 1 minute, every 10 seconds:
37:  *
38:  * <pre>{@code
39:  * DataStream<Tuple2<String, Integer>> in = ...;
40:  * KeyedStream<String, Tuple2<String, Integer>> keyed = in.keyBy(...);
41:  * WindowedStream<Tuple2<String, Integer>, String, TimeWindows> windowed =
42:  *   keyed.window(EventTimeSessionWindows.withGap(Duration.ofMinutes(1)));
43:  * }</pre>
44:  */
45: @PublicEvolving
46: public class EventTimeSessionWindows extends MergingWindowAssigner<Object, TimeWindow> {
47:     private static final long serialVersionUID = 1L;
48: 
49:     protected long sessionTimeout;
50: 
51:     protected EventTimeSessionWindows(long sessionTimeout) {
52:         if (sessionTimeout <= 0) {
53:             throw new IllegalArgumentException(
54:                     "EventTimeSessionWindows parameters must satisfy 0 < size");
55:         }
56: 
57:         this.sessionTimeout = sessionTimeout;
58:     }
59: 
60:     @Override
61:     public Collection<TimeWindow> assignWindows(
62:             Object element, long timestamp, WindowAssignerContext context) {
63:         return Collections.singletonList(new TimeWindow(timestamp, timestamp + sessionTimeout));
64:     }
65: 
66:     @Override
67:     public Trigger<Object, TimeWindow> getDefaultTrigger() {
68:         return EventTimeTrigger.create();
69:     }
70: 
71:     @Override
72:     public String toString() {
73:         return "EventTimeSessionWindows(" + sessionTimeout + ")";
74:     }
75: 
76:     /**
77:      * Creates a new {@code SessionWindows} {@link WindowAssigner} that assigns elements to sessions
78:      * based on the element timestamp.
79:      *
80:      * @param size The session timeout, i.e. the time gap between sessions
81:      * @return The policy.
82:      */
83:     public static EventTimeSessionWindows withGap(Duration size) {
84:         return new EventTimeSessionWindows(size.toMillis());
85:     }
86: 
87:     /**
88:      * Creates a new {@code SessionWindows} {@link WindowAssigner} that assigns elements to sessions
89:      * based on the element timestamp.
90:      *
91:      * @param sessionWindowTimeGapExtractor The extractor to use to extract the time gap from the
92:      *     input elements
93:      * @return The policy.
94:      */
95:     @PublicEvolving
96:     public static <T> DynamicEventTimeSessionWindows<T> withDynamicGap(
97:             SessionWindowTimeGapExtractor<T> sessionWindowTimeGapExtractor) {
98:         return new DynamicEventTimeSessionWindows<>(sessionWindowTimeGapExtractor);
99:     }
100: 
101:     @Override
102:     public TypeSerializer<TimeWindow> getWindowSerializer(ExecutionConfig executionConfig) {
103:         return new TimeWindow.Serializer();
104:     }
105: 
106:     @Override
107:     public boolean isEventTime() {
108:         return true;
109:     }
110: 
111:     /** Merge overlapping {@link TimeWindow}s. */
112:     @Override
113:     public void mergeWindows(
114:             Collection<TimeWindow> windows, MergingWindowAssigner.MergeCallback<TimeWindow> c) {
115:         TimeWindow.mergeWindows(windows, c);
116:     }
117: }
