51: 
52:     protected DynamicEventTimeSessionWindows(
53:             SessionWindowTimeGapExtractor<T> sessionWindowTimeGapExtractor) {
54:         this.sessionWindowTimeGapExtractor = sessionWindowTimeGapExtractor;
