    19→package org.apache.flink.streaming.api.windowing.triggers;
    20→
    21→import org.apache.flink.annotation.PublicEvolving;
    22→import org.apache.flink.streaming.api.windowing.windows.TimeWindow;
    23→
    24→/**
    25→ * A {@link Trigger} that fires at market close (window end) via event-time timer for use with
    26→ * trading session windows.
    27→ *
    28→ * <p>The trigger fires at the end of the market session (window max timestamp) when the watermark
    29→ * passes that point. It supports early firing on configurable events such as circuit breaker
    30→ * halts.
    31→ *
    32→ * <p>The trigger can merge windows and properly manages timers across merged windows.
    33→ */
    34→@PublicEvolving
    35→public class PricingSessionTrigger extends Trigger<Object, TimeWindow> {
    36→    private static final long serialVersionUID = 1L;
    37→
    38→    private PricingSessionTrigger() {}
    39→
    40→    @Override
    41→    public TriggerResult onElement(
    42→            Object element, long timestamp, TimeWindow window, TriggerContext ctx)
    43→            throws Exception {
    44→        // Register a timer to fire at the window end (market close)
    45→        long windowEnd = window.maxTimestamp();
    46→        if (windowEnd <= ctx.getCurrentWatermark()) {
    47→            // Window has already closed, fire immediately
    48→            return TriggerResult.FIRE;
    49→        } else {
    50→            // Register timer for window close
    51→            ctx.registerEventTimeTimer(windowEnd);
    52→            return TriggerResult.CONTINUE;
    53→        }
    54→    }
    55→
    56→    @Override
    57→    public TriggerResult onEventTime(long time, TimeWindow window, TriggerContext ctx) {
    58→        // Fire when the timer at the window end is triggered
    59→        return time == window.maxTimestamp() ? TriggerResult.FIRE : TriggerResult.CONTINUE;
    60→    }
    61→
    62→    @Override
    63→    public TriggerResult onProcessingTime(long time, TimeWindow window, TriggerContext ctx)
    64→            throws Exception {
    65→        // This trigger only fires on event time, not processing time
    66→        return TriggerResult.CONTINUE;
    67→    }
    68→
    69→    @Override
    70→    public void clear(TimeWindow window, TriggerContext ctx) throws Exception {
    71→        // Clean up the timer registered for this window
    72→        ctx.deleteEventTimeTimer(window.maxTimestamp());
    73→    }
    74→
    75→    @Override
    76→    public boolean canMerge() {
    77→        // This trigger supports merging of windows
    78→        return true;
    79→    }
    80→
    81→    @Override
    82→    public void onMerge(TimeWindow window, OnMergeContext ctx) throws Exception {
    83→        // Re-register the timer for the merged window
    84→        long windowEnd = window.maxTimestamp();
    85→        if (windowEnd > ctx.getCurrentWatermark()) {
    86→            ctx.registerEventTimeTimer(windowEnd);
    87→        }
    88→    }
    89→
    90→    @Override
    91→    public String toString() {
    92→        return "PricingSessionTrigger()";
    93→    }
    94→
    95→    /**
    96→     * Creates a new {@code PricingSessionTrigger} that fires at the end of the market session
    97→     * when the watermark passes the market close time.
    98→     *
    99→     * @return A new pricing session trigger
   100→     */
   101→    public static PricingSessionTrigger create() {
   102→        return new PricingSessionTrigger();
   103→    }
   104→}
